-- ============================================================
-- AfriPrix — Données réelles pour le Togo (mars 2026)
-- À exécuter dans l'éditeur SQL de Supabase (onglet SQL Editor)
-- ============================================================

-- ── 0a. Migrations colonnes si absentes ────────────────────
ALTER TABLE products ADD COLUMN IF NOT EXISTS image_url TEXT;
ALTER TABLE products ADD COLUMN IF NOT EXISTS category VARCHAR(100) DEFAULT 'Autre';

-- Fix: nettoyer les URLs Unsplash source dépréciées (les composants utilisent placehold.co en fallback)
UPDATE products SET image_url = NULL WHERE image_url LIKE '%source.unsplash.com%';

-- Ajouter colonnes type et quartier si absentes
ALTER TABLE stores ADD COLUMN IF NOT EXISTS type VARCHAR(100) DEFAULT 'market';
ALTER TABLE stores ADD COLUMN IF NOT EXISTS quartier VARCHAR(255);

-- Supprime les produits sans nom ou avec des noms de test
DELETE FROM prices  WHERE product_id IN (SELECT id FROM products WHERE name IS NULL OR name = '' OR name ILIKE '%test%');
DELETE FROM products WHERE name IS NULL OR name = '' OR name ILIKE '%test%';

-- Supprime les magasins de test
DELETE FROM prices WHERE store_id IN (SELECT id FROM stores WHERE name ILIKE '%test%');
DELETE FROM stores  WHERE name ILIKE '%test%';

