-- ── Vérification ────────────────────────────────────────────
SELECT 'Stores insérés' AS label, COUNT(*) FROM stores WHERE id::text LIKE 'a0000001%';
SELECT 'Produits insérés' AS label, COUNT(*) FROM products WHERE id::text LIKE 'b0000001%';
SELECT 'Prix insérés' AS label, COUNT(*) FROM prices
  WHERE product_id::text LIKE 'b0000001%';
